query:
query GetEvents(
  $code:          String!
  $fightIDs:      [Int]!
  $startTime:     Float!
  $endTime:       Float!
  $type:          EventDataType!
  $hostilityType: HostilityType
) {
  reportData {
    report(code: $code) {
      events(
        fightIDs:        $fightIDs
        startTime:       $startTime
        endTime:         $endTime
        dataType:        $type
        hostilityType:   $hostilityType
        includeResources: true
      ) {
        data
        nextPageTimestamp
      }
    }
  }
}
